#!/usr/bin/env python3 """ Apply Numerical Fixes to All Test Modules === This script applies the critical numerical fixes identified by the user: 1. Replace np.random.complex128 (dtype) with proper RNG usage 2. Replace scipy.linalg.logm with safe_log_unitary for unitaries 3. Adjust tolerance values for eigenvalue tests 4. Improve condition number checks 5. Fix Loschmidt echo implementation This fixes implementation bugs in the quantum gate validation test suite. """ import os import re from pathlib import Path # Utility functions to add to each test module UTILITY_FUNCTIONS = ''' def random_state(N: int) -> np.ndarray: """Generate a random complex state vector.""" rng = np.random.default_rng() real_part = rng.normal(0, 1, N) imag_part = rng.normal(0, 1, N) return real_part + 1j * imag_part def project_unitary(A: np.ndarray) -> np.ndarray: """Project matrix to nearest unitary using polar decomposition.""" U, _ = scipy.linalg.polar(A) return U def safe_log_unitary(U: np.ndarray) -> np.ndarray: """Safely compute matrix logarithm of unitary, avoiding branch cut issues.""" eigenvals, eigenvecs = np.linalg.eig(U) # Take principal branch of log for eigenvalues log_eigenvals = np.log(eigenvals + 1e-15) # Small offset to avoid log(0) # Construct H = i * log(U) such that H is Hermitian log_U = eigenvecs @ np.diag(log_eigenvals) @ eigenvecs.T.conj() return 1j * log_U def bra_ket(psi: np.ndarray, phi: np.ndarray) -> complex: """Compute <psi|||phi> with explicit conjugate transpose.""" return np.conj(psi).T @ phi def loschmidt_echo(psi_0: np.ndarray, U_t: np.ndarray, H: np.ndarray, perturbation_strength: float = 1e-6) -> float: """Compute Loschmidt echo with small perturbation to avoid trivial result.""" # Add small perturbation to Hamiltonian N = len(psi_0) H_pert = H + perturbation_strength * random_state(N*N).reshape(N, N) H_pert = 0.5 * (H_pert + H_pert.T.conj()) # Ensure Hermitian # Forward and backward evolution t_eff = 1.0 # Effective time scale U_forward = scipy.linalg.expm(-1j * H * t_eff) U_backward = scipy.linalg.expm(1j * H_pert * t_eff) # Loschmidt echo psi_final = U_backward @ U_forward @ psi_0 return abs(bra_ket(psi_0, psi_final))**2 ''' def apply_fixes_to_file(filepath: str) -> bool: """Apply numerical fixes to a single test file.""" print(f"Processing {filepath}...") try: with open(filepath, 'r') as f: content = f.read() # Store original content original_content = content # Fix 1: Add utility functions after imports if 'def random_state(' not in content: # Find the last import statement import_lines = [] other_lines = [] in_imports = True for line in content.split('\n'): if line.strip().startswith('import ') or line.strip().startswith('from ') or (in_imports and line.strip().startswith(' ')): import_lines.append(line) elif line.strip() == '': if in_imports: import_lines.append(line) else: other_lines.append(line) else: in_imports = False other_lines.append(line) # Insert utility functions after imports import_section = '\n'.join(import_lines) rest_section = '\n'.join(other_lines) content = import_section + UTILITY_FUNCTIONS + '\n\n' + rest_section # Fix 2: Replace np.random.complex128 with random_state() content = re.sub( r'np\.random\.complex128\(([^)]+)\)', r'random_state(\1)', content ) # Fix 3: Replace scipy.linalg.logm usage for Hamiltonians content = re.sub( r'scipy\.linalg\.logm\(([^)]+)\)', r'safe_log_unitary(\1) / 1j', # Since safe_log_unitary returns i*log(U) content ) # Fix specific Hamiltonian extraction patterns content = re.sub( r'H = 1j \* scipy\.linalg\.logm\(([^)]+)\)', r'H = safe_log_unitary(\1)', content ) content = re.sub( r'H = -1j \* scipy\.linalg\.logm\(([^)]+)\)', r'H = -safe_log_unitary(\1)', content ) # Fix 4: Replace get_rft_basis() usage with projection content = re.sub( r'U = get_rft_basis\(([^)]+)\)', r'U_raw = get_rft_basis(\1)\n U = project_unitary(U_raw)', content ) # Fix 5: Replace conjugate transpose patterns content = re.sub( r'np\.conj\(([^)]+)\)\.T @ ([^)]+)', r'bra_ket(\1, \2)', content ) content = re.sub( r'([^.]+)\.conj\(\)\.T @ ([^)]+)', r'bra_ket(\1, \2)', content ) # Fix 6: Update eigenvalue tolerance checks content = re.sub( r'np\.all\(np\.abs\(spectral_radii - 1\.0\) < self\.tolerance\)', r'np.all(np.abs(spectral_radii - 1.0) < 1e-10)', # Relaxed eigenvalue tolerance content ) # Fix 7: Update condition number checks for unitaries content = re.sub( r'condition_number < 1e6', r'condition_number <= 1 + 1e-8', content ) # Fix 8: Add Loschmidt echo calls content = re.sub( r'echo = abs\(([^.]+)\.conj\(\) @ U_t_dagger @ U_t @ \1\)', r'echo = loschmidt_echo(\1, U_t, H)', content ) # Write back if changes were made if content != original_content: with open(filepath, 'w') as f: f.write(content) print(f" ✓ Applied fixes to {filepath}") return True else: print(f" • No changes needed for {filepath}") return False except Exception as e: print(f" ✗ Error processing {filepath}: {e}") return False def main(): """Apply fixes to all test modules.""" test_files = [ 'test_choi_channel.py', 'test_lie_closure.py', 'test_randomized_benchmarking.py', 'test_spectral_locality.py', 'test_state_evolution_benchmarks.py', 'test_trotter_error.py' ] workspace_dir = Path(__file__).parent print("Applying numerical fixes to remaining test modules...") print("=" * 60) total_files = len(test_files) files_modified = 0 for test_file in test_files: filepath = workspace_dir / test_file if filepath.exists(): if apply_fixes_to_file(str(filepath)): files_modified += 1 else: print(f" ⚠ File not found: {test_file}") print("=" * 60) print(f"Fix application complete: {files_modified}/{total_files} files modified") if files_modified == total_files: print("✓ All numerical fixes applied successfully!") print("||nNext steps:") print("1. Run the complete test suite: python run_quantum_gate_validation.py") print("2. Generate comprehensive validation report") else: print("⚠ Some files may need manual review") if __name__ == "__main__": main() 